<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Falling Sand Sandbox</title>
    <style>
        :root {
            --bg-color: #1a1a1a;
            --panel-bg: #252525;
            --text-color: #e0e0e0;
            --accent: #4CAF50;
            --danger: #f44336;
        }

        body {
            margin: 0;
            padding: 0;
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            overflow: hidden;
        }

        h1 { margin-bottom: 10px; font-weight: 300; letter-spacing: 1px; }

        #controls {
            background-color: var(--panel-bg);
            padding: 15px;
            border-radius: 8px;
            box-shadow: 0 4px 6px rgba(0,0,0,0.3);
            display: flex;
            gap: 10px;
            margin-bottom: 20px;
            flex-wrap: wrap;
            justify-content: center;
        }

        button {
            padding: 8px 16px;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            font-weight: bold;
            transition: transform 0.1s, opacity 0.2s;
            color: #fff;
            text-transform: uppercase;
            font-size: 0.8rem;
        }

        button:hover { opacity: 0.9; transform: translateY(-1px); }
        button:active { transform: translateY(1px); }

        .btn-sand { background-color: #e6c229; color: #333; }
        .btn-water { background-color: #4fc3f7; color: #000; }
        .btn-wall { background-color: #757575; }
        .btn-acid { background-color: #ff6e40; }
        .btn-eraser { background-color: #333; border: 1px solid #555; }
        .btn-clear { background-color: var(--danger); margin-left: auto; }

        #sand-container {
            position: relative;
            box-shadow: 0 0 20px rgba(0,0,0,0.5);
            border: 2px solid #333;
            cursor: crosshair;
        }

        canvas {
            display: block;
            image-rendering: pixelated; /* Crucial for crisp pixels */
        }

        .legend {
            margin-top: 10px;
            font-size: 0.8rem;
            color: #aaa;
            display: flex;
            gap: 15px;
        }
        .legend-item { display: flex; align-items: center; gap: 5px; }
        .dot { width: 10px; height: 10px; border-radius: 2px; display: inline-block; }
    </style>
</head>
<body>

    <h1>Falling Sand Sandbox</h1>

    <div id="controls">
        <button id="mat-sand" class="btn-sand">Sand</button>
        <button id="mat-water" class="btn-water">Water</button>
        <button id="mat-wall" class="btn-wall">Wall</button>
        <button id="mat-acid" class="btn-acid">Acid</button>
        <button id="mat-empty" class="btn-eraser">Eraser</button>
        <button id="clear" class="btn-clear">Clear All</button>
    </div>

    <div id="sand-container">
        <canvas id="sand"></canvas>
    </div>

    <div class="legend">
        <div class="legend-item"><span class="dot" style="background:#e6c229"></span>Sand</div>
        <div class="legend-item"><span class="dot" style="background:#4fc3f7"></span>Water</div>
        <div class="legend-item"><span class="dot" style="background:#757575"></span>Wall</div>
        <div class="legend-item"><span class="dot" style="background:#ff6e40"></span>Acid</div>
    </div>

<script>
/**
 * Falling Sand Simulation Engine
 */

// Configuration
const W = 160; // Width in cells (>=80)
const H = 120; // Height in cells (>=80)
const SCALE = 4; // Visual scaling factor for CSS pixels

// Materials
const MAT_EMPTY = 'empty';
const MAT_SAND = 'sand';
const MAT_WATER = 'water';
const MAT_WALL = 'wall';
const MAT_ACID = 'acid';

// Colors for rendering
const COLORS = {
    [MAT_EMPTY]: '#1a1a1a',
    [MAT_SAND]: '#e6c229',
    [MAT_WATER]: '#4fc3f7',
    [MAT_WALL]: '#757575',
    [MAT_ACID]: '#ff6e40'
};

// Canvas Setup
const canvas = document.getElementById('sand');
const ctx = canvas.getContext('2d');

// Set internal resolution
canvas.width = W;
canvas.height = H;
canvas.style.width = (W * SCALE) + 'px';
canvas.style.height = (H * SCALE) + 'px';

// Grid State
let grid = new Array(W * H).fill(MAT_EMPTY);

// Helper to get index
const idx = (x, y) => x + y * W;

// --- Simulation Logic ---

function tick() {
    // We iterate from bottom to top (y = H-2 down to 0)
    // This ensures particles move at most one cell per step.

    for (let y = H - 2; y >= 0; y--) {
        for (let x = 0; x < W; x++) {
            const i = idx(x, y);
            const mat = grid[i];

            if (mat === MAT_EMPTY || mat === MAT_WALL) continue;

            // --- SAND LOGIC ---
            if (mat === MAT_SAND) {
                const belowIdx = idx(x, y + 1);
                const belowMat = grid[belowIdx];

                // 1. Try to fall straight down
                if (belowMat === MAT_EMPTY || belowMat === MAT_WATER || belowMat === MAT_ACID) {
                    // Swap with liquid or empty
                    grid[i] = belowMat;
                    grid[belowIdx] = MAT_SAND;
                } 
                // 2. If blocked below, try diagonals (randomize order to prevent bias)
                else if (belowMat === MAT_WALL || belowMat === MAT_SAND) {
                    const dirs = [
                        { dx: -1, dy: 1 }, // Down-Left
                        { dx: 1, dy: 1 }   // Down-Right
                    ];
                    // Shuffle directions randomly
                    if (Math.random() < 0.5) dirs.reverse();

                    for (let d of dirs) {
                        const nx = x + d.dx;
                        const ny = y + d.dy;
                        if (nx >= 0 && nx < W && ny >= 0 && ny < H) {
                            const nIdx = idx(nx, ny);
                            const nMat = grid[nIdx];

                            // Can slide into empty or liquid
                            if (nMat === MAT_EMPTY || nMat === MAT_WATER || nMat === MAT_ACID) {
                                grid[i] = nMat;
                                grid[nIdx] = MAT_SAND;
                                break; // Moved, stop checking other directions
                            }
                        }
                    }
                }
            }

            // --- WATER LOGIC ---
            else if (mat === MAT_WATER) {
                const belowIdx = idx(x, y + 1);
                const belowMat = grid[belowIdx];

                // 1. Try to fall straight down
                if (belowMat === MAT_EMPTY || belowMat === MAT_SAND || belowMat === MAT_ACID) {
                    grid[i] = belowMat;
                    grid[belowIdx] = MAT_WATER;
                } 
                // 2. If blocked below, spread horizontally
                else {
                    const dirs = [
                        { dx: -1, dy: 0 }, // Left
                        { dx: 1, dy: 0 }   // Right
                    ];
                    if (Math.random() < 0.5) dirs.reverse();

                    for (let d of dirs) {
                        const nx = x + d.dx;
                        const ny = y;
                        if (nx >= 0 && nx < W) {
                            const nIdx = idx(nx, ny);
                            const nMat = grid[nIdx];

                            // Spread into empty or acid (acid sinks water usually in real life, but here we treat as fluid mixing)
                            // Let's allow spreading into empty. 
                            if (nMat === MAT_EMPTY || nMat === MAT_ACID) {
                                grid[i] = nMat;
                                grid[nIdx] = MAT_WATER;
                                break;
                            }
                        }
                    }
                }
            }

            // --- ACID LOGIC ---
            else if (mat === MAT_ACID) {
                const belowIdx = idx(x, y + 1);
                const belowMat = grid[belowIdx];

                // 1. Try to fall straight down (like water)
                if (belowMat === MAT_EMPTY || belowMat === MAT_SAND || belowMat === MAT_WALL) {
                    // If hitting wall/sand, we might dissolve it or just sit? 
                    // Prompt: "dissolves sand or wall cells it touches below or beside"

                    // Check dissolution first if blocked by solid
                    if (belowMat === MAT_WALL || belowMat === MAT_SAND) {
                        // Chance to dissolve
                        if (Math.random() < 0.15) { 
                            grid[i] = MAT_EMPTY; // Acid disappears
                            grid[belowIdx] = MAT_EMPTY; // Solid disappears
                            continue; // Skip movement logic for this tick step
                        } else {
                             // If it doesn't dissolve, does it swap? Usually acid sits on top.
                             // But prompt says "moves like water". Let's assume it swaps if empty, 
                             // but stays if blocked by solid unless dissolved.
                             // However, to make it fun, let's allow it to sit or move sideways.
                        }
                    }

                    // Swap with Empty (falling)
                    if (belowMat === MAT_EMPTY) {
                        grid[i] = belowMat;
                        grid[belowIdx] = MAT_ACID;
                    } 
                    // Spread horizontally if blocked by solid (wall/sand) or empty?
                    // Usually acid flows like water.
                } else if (belowMat === MAT_WATER || belowMat === MAT_ACID) {
                     // Swap with liquid
                     grid[i] = belowMat;
                     grid[belowIdx] = MAT_ACID;
                } 
                // 2. If blocked below, spread horizontally
                else {
                    const dirs = [
                        { dx: -1, dy: 0 },
                        { dx: 1, dy: 0 }
                    ];
                    if (Math.random() < 0.5) dirs.reverse();

                    for (let d of dirs) {
                        const nx = x + d.dx;
                        const ny = y;
                        if (nx >= 0 && nx < W) {
                            const nIdx = idx(nx, ny);
                            const nMat = grid[nIdx];

                            // Spread into empty or sand/wall (dissolving)
                            if (nMat === MAT_EMPTY || nMat === MAT_SAND || nMat === MAT_WALL) {
                                // Dissolve check for solids
                                if (nMat !== MAT_EMPTY && Math.random() < 0.15) {
                                    grid[i] = MAT_EMPTY;
                                    grid[nIdx] = MAT_EMPTY;
                                    continue;
                                }

                                grid[i] = nMat;
                                grid[nIdx] = MAT_ACID;
                                break;
                            }
                        }
                    }
                }
            }
        }
    }
}

// --- Rendering ---

function draw() {
    // Clear background
    ctx.fillStyle = COLORS[MAT_EMPTY];
    ctx.fillRect(0, 0, W, H);

    // Draw grid cells
    for (let i = 0; i < grid.length; i++) {
        const mat = grid[i];
        if (mat !== MAT_EMPTY) {
            ctx.fillStyle = COLORS[mat];

            // Optional: Add a tiny bit of noise or shading to make it look less flat
            // but for performance we stick to solid fill.

            // Draw slightly smaller rect for "pixel" feel
            const x = i % W;
            const y = Math.floor(i / W);

            ctx.fillRect(x, y, 1, 1);
        }
    }
}

// --- Interaction & API ---

const sim = {
    w: W,
    h: H,

    tick: function(n) {
        for(let k=0; k<n; k++) tick();
    },

    get: function(x, y) {
        if (x < 0 || x >= W || y < 0 || y >= H) return MAT_EMPTY;
        return grid[idx(x, y)];
    },

    set: function(x, y, material) {
        if (x < 0 || x >= W || y < 0 || y >= H) return;
        const i = idx(x, y);
        // Don't overwrite walls with empty unless erasing specifically? 
        // Prompt says "place one cell". Let's allow overwriting.
        grid[i] = material;
    },

    clear: function() {
        grid.fill(MAT_EMPTY);
    }
};

// --- UI Wiring ---

const buttons = {
    sand: document.getElementById('mat-sand'),
    water: document.getElementById('mat-water'),
    wall: document.getElementById('mat-wall'),
    acid: document.getElementById('mat-acid'),
    empty: document.getElementById('mat-empty'),
    clear: document.getElementById('clear')
};

let isDrawing = false;
let currentMat = MAT_SAND;

function paint(x, y) {
    // Convert mouse coordinates to grid coordinates
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    const mx = Math.floor((x - rect.left) * scaleX);
    const my = Math.floor((y - rect.top) * scaleY);

    // Brush size (radius 1 for precision, maybe 2 for easier painting)
    const r = 1; 

    for(let dy = -r; dy <= r; dy++) {
        for(let dx = -r; dx <= r; dx++) {
            if(dx*dx + dy*dy <= r*r) {
                sim.set(mx + dx, my + dy, currentMat);
            }
        }
    }
}

// Mouse Events
canvas.addEventListener('mousedown', (e) => {
    isDrawing = true;
    paint(e.clientX, e.clientY);
});

window.addEventListener('mouseup', () => isDrawing = false);

canvas.addEventListener('mousemove', (e) => {
    if (isDrawing) {
        paint(e.clientX, e.clientY);
    }
});

// Button Listeners
buttons.sand.onclick = () => currentMat = MAT_SAND;
buttons.water.onclick = () => currentMat = MAT_WATER;
buttons.wall.onclick = () => currentMat = MAT_WALL;
buttons.acid.onclick = () => currentMat = MAT_ACID;
buttons.empty.onclick = () => currentMat = MAT_EMPTY;

buttons.clear.onclick = () => {
    sim.clear();
};

// Animation Loop
function loop() {
    // Run simulation steps per frame (e.g. 1 step for real-time feel)
    tick(1); 
    draw();
    requestAnimationFrame(loop);
}

// Start
loop();

</script>
</body>
</html>
